import { createFileRoute } from "@tanstack/react-router";
import { useGetPublicActionPageQueryOptions } from "@workspace/api-client/public";
import type { ActionPageDesignConfiguration } from "@workspace/api-client/types/actionPage";

export const Route = createFileRoute("/lead/$slug/$token")({
  component: RouteComponent,
  errorComponent: LeadErrorComponent,
  loader: async ({ context: { queryClient }, params: { slug, token } }) => {
    const options = useGetPublicActionPageQueryOptions({
      actionPageSlug: token,
      accountSlug: slug,
    });
    const actionPage = await queryClient.ensureQueryData(options);

    return { actionPage };
  },
});

const setTheme = (designConfiguration: ActionPageDesignConfiguration) => {
  const colorMap = new Map<string, string>([
    [
      "--primary",
      designConfiguration.headerColor ||
        // default slate-700
        "oklch(37.2% 0.044 257.287)",
    ],
    ["--primary-bg", designConfiguration.backgroundColor || "#FFFFFF"],
    [
      "--secondary",
      designConfiguration.actionElementColorPrimary ||
        // default slate-700
        "oklch(37.2% 0.044 257.287)",
    ],
    ["--secondary-bg", designConfiguration.backgroundColor || "#FFFFFF"],
  ]);
  colorMap.forEach((value, key) => {
    document.documentElement.style.setProperty(key, value);
  });
};

function RouteComponent() {
  const { actionPage } = Route.useLoaderData();
  console.log(actionPage.designConfiguration);
  setTheme(actionPage.designConfiguration);

  return (
    <div className="flex flex-col items-center rounded-lg bg-white p-12 shadow-md">
      <h1>{actionPage.headerTitleText}</h1>
      {actionPage.description && <p>{actionPage.description}</p>}
    </div>
  );
}

function LeadErrorComponent({ error }: { error: Error }) {
  return <div>Error: {error.message}</div>;
}

